<section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">BUSINESS MODULE</span><h1>Career Listings</h1></div></div><form class="admin-panel admin-form" method="post" action="<?=url('admin/business-jobs')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=e($editing['id']??'')?>"><h2><?=$editing?'Edit':'Create'?> Job</h2><div class="form-grid"><?php foreach(['title'=>'Title','slug'=>'URL slug','department'=>'Department','location'=>'Location','vacancy'=>'Vacancies','salary_range'=>'Salary range','application_deadline'=>'Deadline']as$n=>$l):?><label><?=$l?><input name="<?=$n?>" value="<?=e($editing[$n]??($n==='vacancy'?1:''))?>" <?=$n==='application_deadline'?'type="date"':''?> required></label><?php endforeach;?><label>Employment type<select name="employment_type"><?php foreach(['full_time','part_time','contract','internship']as$x):?><option value="<?=$x?>" <?=($editing['employment_type']??'')===$x?'selected':''?>><?=ucwords(str_replace('_',' ',$x))?></option><?php endforeach;?></select></label></div><?php foreach(['summary','responsibilities','requirements']as$n):?><label><?=ucfirst($n)?><textarea name="<?=$n?>" required><?=e($editing[$n]??'')?></textarea></label><?php endforeach;?><label><input type="checkbox" name="is_published" <?=($editing['is_published']??1)?'checked':''?>> Published</label><button class="btn">Save Job</button></form><div class="admin-panel table-wrap"><table><thead><tr><th>Job</th><th>Department</th><th>Deadline</th><th>Published</th><th></th></tr></thead><tbody><?php foreach($rows as$x):?><tr><td><?=e($x['title'])?></td><td><?=e($x['department'])?></td><td><?=e($x['application_deadline'])?></td><td><?=$x['is_published']?'Yes':'No'?></td><td><a href="<?=url('admin/business-jobs?id='.$x['id'])?>">Edit</a></td></tr><?php endforeach;?></tbody></table></div></div></section>
